import{_ as a,c as e,o as l,R as o}from"./chunks/framework.Cfz5bXfs.js";const q=JSON.parse('{"title":"机器学习","description":"","frontmatter":{},"headers":[],"relativePath":"code/MachineLearning.md","filePath":"code/MachineLearning.md","lastUpdated":1701168739000}'),i={name:"code/MachineLearning.md"},t=o('<h1 id="机器学习" tabindex="-1">机器学习 <a class="header-anchor" href="#机器学习" aria-label="Permalink to &quot;机器学习&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">快速入门</p><p>推荐课程：<a href="https://www.bilibili.com/video/BV1Wv411h7kN" target="_blank" rel="noreferrer">李宏毅2023春机器学习课程</a></p></div><h2 id="引入" tabindex="-1">引入 <a class="header-anchor" href="#引入" aria-label="Permalink to &quot;引入&quot;">​</a></h2><ol><li><p><code>ChatGPT</code> 实现基本原理：文字接龙；</p><p><code>BERT</code> 实现的基本原理是：文字填空。</p></li><li><p>预训练模型→下游模型</p><p>预训练模型（基石模型）：自督导式学习。</p><p>下游模型：督导式学习→增强式学习（由人类干涉）。</p></li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p><code>ChatGPT</code>：自督导式→督导式学习→增强式学习。</p><p>自督导式：学会文字接龙；</p><p>督导式学习：学会正确的文字接龙；</p><p>增强式学习：学会更好的文字接龙。</p></div><h2 id="基础" tabindex="-1">基础 <a class="header-anchor" href="#基础" aria-label="Permalink to &quot;基础&quot;">​</a></h2><ol><li><p>机器学习 ≈ 机器自动找到一个函式。</p></li><li><p>根据函式的输出分类：</p><ul><li><p>回归：函式的输出是一个数值；</p></li><li><p>分类：函式的输出是一个类别。</p></li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p><code>ChatGPT</code>：属于分类，把生成式学习拆解成多个分类问题。</p></div><ol start="3"><li><p>找函式的三个步骤：</p><ul><li><p>设定范围 —— 定出候选函式的集合（Model）；</p></li><li><p>设定标准 —— 定出【评量函式好坏】的标准（Loss）；</p></li><li><p>达成目标 —— 找出最好的函式。</p></li></ul></li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p><code>CNN,RNN,Transformer(类神经网络结构)</code> 就是候选函式的集合。</p></div><h2 id="生成式学习" tabindex="-1">生成式学习 <a class="header-anchor" href="#生成式学习" aria-label="Permalink to &quot;生成式学习&quot;">​</a></h2><h3 id="两种策略" tabindex="-1">两种策略 <a class="header-anchor" href="#两种策略" aria-label="Permalink to &quot;两种策略&quot;">​</a></h3><blockquote><p>各个击破、一次到位。</p></blockquote><ol><li><p>各个击破：</p><ul><li>速度较慢：一次只生成一个元素，每个元素都要等前一个元素生成。</li><li>品质更好。</li></ul></li><li><p>一次到位：</p><ul><li><p>速度快：只要有足够的平行算力，就可以完全生成。</p></li><li><p>品质较差。</p></li></ul></li></ol><p>推荐：各个击破 + 一次到位</p><ul><li>以各个击破为基础，再一次到位；</li><li>N次到位。</li></ul><h3 id="两种不同期待" tabindex="-1">两种不同期待 <a class="header-anchor" href="#两种不同期待" aria-label="Permalink to &quot;两种不同期待&quot;">​</a></h3><ol><li><p>成为通才：适用于各种任务，可以快速开发出新的功能；</p></li><li><p>成为专才：在单一任务上会比通才较好。</p></li></ol><h3 id="对预训练的模型进行改造" tabindex="-1">对预训练的模型进行改造 <a class="header-anchor" href="#对预训练的模型进行改造" aria-label="Permalink to &quot;对预训练的模型进行改造&quot;">​</a></h3><ol><li>微调：把模型的原来参数当作初始化参数，使用梯度下降法对模型进行微调。</li><li>Adapter(适配器)：不改动模型的参数，为模型提供额外的模组（适应更多的任务）。</li></ol><h2 id="in-context-learning" tabindex="-1">In-context Learning <a class="header-anchor" href="#in-context-learning" aria-label="Permalink to &quot;In-context Learning&quot;">​</a></h2><blockquote><p>情境学习</p></blockquote><p>为机器提供标注的范例进行“学习” —— 模型其实本来就会情境分析，只是需要被指出要做情境任务。</p><blockquote><p>提供过多的错误示例，可能会导致模型自动学习到错误的知识。</p></blockquote><h2 id="instruction-tuning" tabindex="-1">Instruction-tuning <a class="header-anchor" href="#instruction-tuning" aria-label="Permalink to &quot;Instruction-tuning&quot;">​</a></h2><blockquote><p>微调</p></blockquote><p>激发语言模型 的理解能力，它通过给出更明显的指令，让模型去做出正确的行动。指示学习的优点是它经过多任务的微调后，也能够在其他任务上做 <code>zero-shot</code>。</p><h2 id="chain-of-thought-cot" tabindex="-1">Chain of Thought （CoT） <a class="header-anchor" href="#chain-of-thought-cot" aria-label="Permalink to &quot;Chain of Thought （CoT）&quot;">​</a></h2><p>思维链(<code>Chain-of-thought</code>，<code>CoT</code>)是指令示范的一种特殊情况，它通过引发对话代理的逐步推理来生成输出。 使用 <code>CoT</code> 微调的模型使用带有逐步推理的人工标注的指令数据集。</p><h2 id="大模型-大资料" tabindex="-1">大模型+大资料 <a class="header-anchor" href="#大模型-大资料" aria-label="Permalink to &quot;大模型+大资料&quot;">​</a></h2><blockquote><p>产生质的变化，模型会突然顿悟。</p></blockquote><h3 id="大模型的顿悟时刻" tabindex="-1">大模型的顿悟时刻 <a class="header-anchor" href="#大模型的顿悟时刻" aria-label="Permalink to &quot;大模型的顿悟时刻&quot;">​</a></h3><p>模型的效果不是随着模型参数量变多而慢慢变好，而是在某一个瞬间，模型“顿悟”了</p><h3 id="大资料-两种认知" tabindex="-1">大资料-两种认知 <a class="header-anchor" href="#大资料-两种认知" aria-label="Permalink to &quot;大资料-两种认知&quot;">​</a></h3><p>语言模型一般需要两种认知</p><ul><li>一种是对语言本身语法、文法的认知 <ul><li>这一部分不需要很多的语料，有一些资料供学习就够了</li></ul></li><li>另一种是对语言背后世界运行规律的认知 <ul><li>这一部分就需要大量的语料喂入了</li></ul></li></ul><h3 id="大资料筛选" tabindex="-1">大资料筛选 <a class="header-anchor" href="#大资料筛选" aria-label="Permalink to &quot;大资料筛选&quot;">​</a></h3><ul><li>过滤有害内容</li><li>去除无关资料</li><li>用规则去除低品质的资料</li><li>去除重复的资料</li><li>要及时去除测试资料</li></ul><h3 id="knn-lm" tabindex="-1">KNN LM <a class="header-anchor" href="#knn-lm" aria-label="Permalink to &quot;KNN LM&quot;">​</a></h3><p><code>knn</code> 又称为K临近分类算法。简单地说，<code>K</code>-近邻算法采用测量不同特征值之间的距离方法进行分类（<code>k-Nearest Neighbor</code>，<code>KNN</code>）。“物以类聚，人以群分”，这是这个算法的一个思想。近邻算法，即是给定一个训练数据集，对新的输入实例，在训练数据集中找到与该实例最邻近的K个实例，这K个实例的多数属于某个类，就把该输入实例分类到这个类中。</p><h2 id="图像生成" tabindex="-1">图像生成 <a class="header-anchor" href="#图像生成" aria-label="Permalink to &quot;图像生成&quot;">​</a></h2><blockquote><p>图像版 GTP</p></blockquote><h3 id="各个击破" tabindex="-1">各个击破 <a class="header-anchor" href="#各个击破" aria-label="Permalink to &quot;各个击破&quot;">​</a></h3><p>一个一个像素地生成，耗时过长。</p><h3 id="一次到位" tabindex="-1">一次到位 <a class="header-anchor" href="#一次到位" aria-label="Permalink to &quot;一次到位&quot;">​</a></h3><p>一次性生成一张图片。</p><h2 id="stable-diffusion-imagen" tabindex="-1">Stable Diffusion / Imagen <a class="header-anchor" href="#stable-diffusion-imagen" aria-label="Permalink to &quot;Stable Diffusion / Imagen&quot;">​</a></h2><p>文字模型 --&gt; 中间产物（图片的压缩版本） --&gt; 还原成原来图片</p>',48),n=[t];function r(c,h,d,p,s,u){return l(),e("div",null,n)}const k=a(i,[["render",r]]);export{q as __pageData,k as default};
